exercises.solution_code:
def call_with_retry(fetch, attempts):
    # Call the zero-argument collaborator `fetch`. If it raises, try again,
    # up to `attempts` total calls. Return the first successful result; if every
    # attempt fails, re-raise the last exception.
    if attempts < 1:
        raise ValueError("attempts must be at least 1")
    last_exc = None
    for _ in range(attempts):
        try:
            return fetch()
        except Exception as exc:  # noqa: BLE001 - retry on any failure
            last_exc = exc
    raise last_exc
